/**
 * Manager autograph PNGs — Avi & Ron's signature stamps for אישור מנהל תיק.
 *
 * Embedded as base64 so they're bundled with the Next.js server build and
 * available on Railway without any runtime filesystem dependency. These are
 * the firm stamp + handwritten signature scrawls extracted from the originals
 * Avi/Ron provided (see /tmp/bitan-autograph-extract for source PDFs).
 *
 * Used by auto-stamp.ts to apply the office counter-signature automatically
 * the moment the client finishes signing — replaces the manual 2Sign routine
 * step that previously required Avi/Ron to log in and counter-sign each POA.
 */

const AVI_PNG_BASE64 = ''

const RON_PNG_BASE64 = ''

export type ManagerName = 'avi' | 'ron'

export interface ManagerStamp {
  /** PNG bytes for embedding via pdf-lib */
  png: Buffer
  /** Display name for stamp metadata */
  fullName: string
}

export function getManagerStamp(manager: ManagerName): ManagerStamp {
  if (manager === 'avi') {
    return {
      png: Buffer.from(AVI_PNG_BASE64, 'base64'),
      fullName: 'אבי ביטן',
    }
  }
  return {
    png: Buffer.from(RON_PNG_BASE64, 'base64'),
    fullName: 'רון ביטן',
  }
}

/**
 * Map account-manager string from Summit to the autograph owner.
 * Mirrors resolveOfficeSigner() in types.ts but returns the stamp asset key.
 */
export function resolveStampOwner(accountManager?: string): ManagerName {
  const m = (accountManager || '').trim()
  if (m.includes('רון')) return 'ron'
  // Default to Avi (~55% of clients per CLAUDE.md system prompt)
  return 'avi'
}
